

import { NextResponse } from "next/server";
import path from "path";
import fs from "fs";
import { writeFile } from "fs/promises";
import pdfParse from "pdf-parse";
import OpenAI from "openai";

const uploadDir = path.join(process.cwd(), "public/uploads");

// Ensure the upload directory exists
if (!fs.existsSync(uploadDir)) {
  fs.mkdirSync(uploadDir, { recursive: true });
}

// Function to save the uploaded PDF
const saveFile = async (file: File) => {
  const fileName = `${Date.now()}-${file.name.replace(/\s+/g, "_")}`;
  const filePath = path.join(uploadDir, fileName);

  const buffer = Buffer.from(await file.arrayBuffer());
  await writeFile(filePath, buffer);

  return filePath;
};

// Function to extract text from the uploaded PDF
const extractTextFromPDF = async (filePath: string) => {
  try {
    const pdfBuffer = fs.readFileSync(filePath);
    const pdfData = await pdfParse(pdfBuffer);
    return pdfData.text || "No text found in PDF";
  } catch (error) {
    console.error("Error extracting text from PDF:", error);
    return "Error extracting text";
  }
};

// Function to analyze the extracted text with AI
const analyzePDFWithAI = async (text: string) => {
  try {
    const openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY });

    const response = await openai.chat.completions.create({
      model: "gpt-4-turbo",
      messages: [
        {
          role: "user",
          content: `Extract the following details from the given student document:
            - Full Name
            - Marks (subject-wise)
            - Percentage
            - Board Name
            - Other important details

            Text from PDF:
            """${text}"""
          `,
        },
      ],
      temperature: 0.3,
    });

    return response.choices[0]?.message?.content?.trim() || "No structured details found.";
  } catch (error) {
    console.error("AI Processing Error:", error);
    return "AI processing failed.";
  }
};

// API Route to handle PDF upload & scanning
export async function POST(req: Request) {
  try {
    const formData = await req.formData();
    const file = formData.get("pdf") as File;

    if (!file || !file.name.toLowerCase().endsWith(".pdf")) {
      return NextResponse.json({ error: "Invalid PDF file" }, { status: 400 });
    }

    // Save the uploaded file
    const filePath = await saveFile(file);

    // Extract text from the PDF
    const extractedText = await extractTextFromPDF(filePath);

    // Use AI to extract structured details
    const extractedDetails = await analyzePDFWithAI(extractedText);

    return NextResponse.json({
      message: "PDF scanned successfully",
      extractedText,
      extractedDetails,
    });
  } catch (error) {
    console.error("Error processing PDF:", error);
    return NextResponse.json({ error: "Internal Server Error" }, { status: 500 });
  }
}
